// src/components/common/RoleBasedNav.js
import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useRole } from '../../context/RoleContext';
import PermissionGate from './PermissionGate';
import './RoleBasedNav.css';

const RoleBasedNav = () => {
    const { user, logout } = useAuth();
    const { userRole, isRole } = useRole();
    const navigate = useNavigate();

    const handleLogout = () => {
        logout();
        navigate('/');
    };

    const getRoleIcon = () => {
        switch(userRole) {
            case 'master_admin':
                return '👑';
            case 'doctor':
                return '👨‍⚕️';
            case 'nurse':
                return '👩‍⚕️';
            case 'diagnostic_staff':
            case 'lab_technician':
            case 'radiologist':
                return '🔬';
            case 'therapeutic_staff':
            case 'physiotherapist':
            case 'nutritionist':
                return '💪';
            case 'pharmacist':
                return '💊';
            case 'receptionist':
                return '📋';
            case 'billing_officer':
                return '💰';
            case 'ict_admin':
                return '💻';
            case 'hr_admin':
                return '👥';
            case 'department_head':
                return '👔';
            default:
                return '👤';
        }
    };

    const getRoleDisplayName = () => {
        switch(userRole) {
            case 'master_admin':
                return 'Master Admin';
            case 'doctor':
                return 'Doctor';
            case 'nurse':
                return 'Nurse';
            case 'diagnostic_staff':
                return 'Diagnostic Staff';
            case 'lab_technician':
                return 'Lab Technician';
            case 'radiologist':
                return 'Radiologist';
            case 'therapeutic_staff':
                return 'Therapeutic Staff';
            case 'physiotherapist':
                return 'Physiotherapist';
            case 'nutritionist':
                return 'Nutritionist';
            case 'pharmacist':
                return 'Pharmacist';
            case 'receptionist':
                return 'Receptionist';
            case 'billing_officer':
                return 'Billing Officer';
            case 'ict_admin':
                return 'ICT Admin';
            case 'hr_admin':
                return 'HR Admin';
            case 'department_head':
                return 'Department Head';
            default:
                return userRole?.replace('_', ' ').toUpperCase() || 'Patient';
        }
    };

    const getAvatarColor = () => {
        switch(userRole) {
            case 'master_admin': return '#e74c3c';
            case 'doctor': return '#3498db';
            case 'nurse': return '#1abc9c';
            case 'pharmacist': return '#9b59b6';
            case 'receptionist': return '#f39c12';
            default: return '#27ae60';
        }
    };

    return (
        <>
            {/* Welcome Banner */}
            <div className="welcome-banner">
                <div className="welcome-content">
                    <div className="welcome-text">
                        <h2>Welcome, {user?.username}!</h2>
                        <div className="user-badge">
                            <span className="role-badge">{getRoleDisplayName()}</span>
                            <span className="health-id-badge">
                                <span className="health-id-icon">🆔</span>
                                Health Record ID: {user?.healthRecordId}
                            </span>
                        </div>
                    </div>
                </div>
            </div>

            {/* Navigation Bar */}
            <nav className="role-nav">
                <div className="nav-container">
                    <div className="nav-brand">
                        <Link to={isRole('master_admin') ? '/admin' : '/dashboard'} className="brand-link">
                        </Link>
                    </div>
                    
                    <div className="nav-menu">
                        {/* Master Admin Navigation */}
                        {isRole('master_admin') ? (
                            <>
                                <Link to="/admin" className="nav-link">
                                    <span className="nav-icon">👑</span>
                                    <span className="nav-text">Admin Dashboard</span>
                                </Link>
                                <Link to="/admin/roles" className="nav-link">
                                    <span className="nav-icon">⚙️</span>
                                    <span className="nav-text">Manage Roles</span>
                                </Link>
                                <Link to="/admin/verifications" className="nav-link">
                                    <span className="nav-icon">✅</span>
                                    <span className="nav-text">Verifications</span>
                                </Link>
                                <Link to="/admin" className="nav-link">
                                    <span className="nav-icon">👥</span>
                                    <span className="nav-text">All Users</span>
                                </Link>
                            </>
                        ) : (
                            <>
                                <Link to="/dashboard" className="nav-link">
                                    <span className="nav-icon">📊</span>
                                    <span className="nav-text">Dashboard</span>
                                </Link>
                                
                                {/* Patient Management */}
                                {(isRole('receptionist') || isRole('nurse') || isRole('doctor') || 
                                  isRole('therapeutic_staff') || isRole('diagnostic_staff')) && (
                                    <Link to="/patients" className="nav-link">
                                        <span className="nav-icon">👥</span>
                                        <span className="nav-text">Patient Management</span>
                                    </Link>
                                )}
                                
                                {/* Appointments */}
                                <PermissionGate permissions={['view_all_appointments', 'create_appointments', 'schedule_appointments']}>
                                    <Link to="/appointments" className="nav-link">
                                        <span className="nav-icon">📅</span>
                                        <span className="nav-text">Appointments</span>
                                    </Link>
                                </PermissionGate>
                                
                                {/* Prescriptions */}
                                <PermissionGate permissions={['view_all_prescriptions', 'create_prescriptions']}>
                                    <Link to="/prescriptions" className="nav-link">
                                        <span className="nav-icon">💊</span>
                                        <span className="nav-text">Prescriptions</span>
                                    </Link>
                                </PermissionGate>
                                
                                {/* Lab Requests */}
                                <PermissionGate permissions={['view_lab_requests', 'update_lab_results']}>
                                    <Link to="/lab-requests" className="nav-link">
                                        <span className="nav-icon">🔬</span>
                                        <span className="nav-text">Lab Requests</span>
                                    </Link>
                                </PermissionGate>
                                
                                {/* Billing */}
                                <PermissionGate permissions={['view_invoices', 'create_invoices']}>
                                    <Link to="/billing" className="nav-link">
                                        <span className="nav-icon">💰</span>
                                        <span className="nav-text">Billing</span>
                                    </Link>
                                </PermissionGate>
                            </>
                        )}
                    </div>
                    
                    {/* User Avatar - Far Right */}
                    <div className="nav-user">
                        <div className="user-dropdown">
                            <div className="user-avatar-circle" style={{ background: getAvatarColor() }}>
                                <span className="avatar-icon">{getRoleIcon()}</span>
                            </div>
                            <div className="dropdown-menu">
                                <Link to="/profile" className="dropdown-item">
                                    <span className="dropdown-icon">👤</span>
                                    Profile
                                </Link>
                                <Link to="/settings" className="dropdown-item">
                                    <span className="dropdown-icon">⚙️</span>
                                    Settings
                                </Link>
                                <div className="dropdown-divider"></div>
                                <button onClick={handleLogout} className="dropdown-item logout-item">
                                    <span className="dropdown-icon">🚪</span>
                                    Logout
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            </nav>
        </>
    );
};

export default RoleBasedNav;
